+    /// Track expert usage and update hot cache statistics
+    /// Returns true if expert is already resident (cache hit)
+    pub fn trackExpertUsage(self: *Self, expert_idx: u32) bool {
+        if (!self.hot_cache_enabled) return false;
+
+        self.hot_expert_hits[expert_idx] += 1;
+
+        if (self.hot_expert_resident[expert_idx]) {
+            self.hot_cache_total_hits += 1;
+            return true; // Cache hit - expert already in VRAM
+        }
+
+        self.hot_cache_total_misses += 1;
+        return false; // Cache miss - need to load from SSD
+    }
+
+    /// Determine which experts should be kept hot based on usage frequency
+    /// Returns sorted list of top N expert indices
+    pub fn getHotExperts(self: *Self) [8]u8 {
+        // Simple selection: find top N experts by hit count
+        var sorted: [8]u8 = .{ 0, 1, 2, 3, 4, 5, 6, 7 };
+
+        // Bubble sort by hits (descending) - simple and 8 elements is tiny
+        for (0..8) |_| {
+            for (0..7) |j| {
+                if (self.hot_expert_hits[sorted[j]] < self.hot_expert_hits[sorted[j + 1]]) {
+                    const tmp = sorted[j];
+                    sorted[j] = sorted[j + 1];
+                    sorted[j + 1] = tmp;
+                }
+            }
+        }
+
+        return sorted;
+    }
+
+    /// Mark expert as resident in VRAM (after loading)
+    pub fn markExpertResident(self: *Self, expert_idx: u32, resident: bool) void {
+        self.hot_expert_resident[expert_idx] = resident;
+    }
+
+    /// Get hot cache statistics
+    pub fn getHotCacheStats(self: *Self) struct { hits: u64, misses: u64, hit_rate: f32 } {
+        const total = self.hot_cache_total_hits + self.hot_cache_total_misses;
+        const hit_rate = if (total > 0)
+            @as(f32, @floatFromInt(self.hot_cache_total_hits)) / @as(f32, @floatFromInt(total))
+        else
+            0.0;
+        return .{
+            .hits = self.hot_cache_total_hits,
+            .misses = self.hot_cache_total_misses,
+            .hit_rate = hit_rate,
+        };
+    }
+
+    /// Log hot cache performance
+    pub fn logHotCacheStats(self: *Self) void {
+        const stats = self.getHotCacheStats();
+        if (stats.hits + stats.misses > 0) {
+            log.info("Hot Expert Cache: {d} hits, {d} misses, {d:.1}% hit rate", .{
+                stats.hits,
+                stats.misses,
+                stats.hit_rate * 100.0,
+            });
+
+            // Log which experts are hot
+            const hot = self.getHotExperts();
+            log.info("Top experts by usage: #{d} ({d}), #{d} ({d}), #{d} ({d}), #{d} ({d})", .{
+                hot[0], self.hot_expert_hits[hot[0]],
+                hot[1], self.hot_expert_hits[hot[1]],
+                hot[2], self.hot_expert_hits[hot[2]],
+                hot[3], self.hot_expert_hits[hot[3]],
+            });
+        }
+    }
+
